mapper.select:
SELECT q.*, u.USER_NAME 
FROM QNA_BOARD q
LEFT JOIN USER_ACCOUNT u ON UPPER(q.USER_ID) = UPPER(u.USER_ID) WHERE q.QNA_IDX = #{qna_idx}

mapper.insert:
INSERT INTO QNA_BOARD (
    QNA_IDX, TITLE, USER_ID, CONTENT, COUNT, QNA_STATUS, CREATED_AT
) VALUES (
    QNA_BOARD_SEQ.NEXTVAL, #{title}, #{user_id}, #{content, jdbcType=CLOB}, 0, 'WAITING', SYSDATE
)

mapper.update:
UPDATE QNA_BOARD 
SET TITLE = #{title}, 
    CONTENT = #{content, jdbcType=CLOB}
WHERE QNA_IDX = #{qna_idx}
